import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"火麟剑","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/火麟剑.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/火麟剑.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/火麟剑.md"};function l(_,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"火麟剑",tabindex:"-1"},[s("火麟剑 "),e("a",{class:"header-anchor",href:"#火麟剑","aria-label":'Permalink to "火麟剑"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"灵魂蓝调014")])])],-1),o('<h1 id="火麟剑-1" tabindex="-1">火麟剑 <a class="header-anchor" href="#火麟剑-1" aria-label="Permalink to &quot;火麟剑&quot;">​</a></h1><p>火麟剑<br> C+2000<br> 南山巅上火麟剑，北海潜深雪饮寒。<br> 可怜两锋未缘见，雪刀封隐孤剑鸣。<br> 火麟剑乃是与雪饮刀齐名的神兵利器，相传为断家先祖，天下第一剑“断正贤”在力战四处为祸的火麒麟后，得其一块鳞甲，镶于剑身而成，位列【七武器】与【十二惊惶】之中。<br> 火麟剑上镶嵌的鳞甲带有麒麟之魔性，能助使用者提升功力，但是也会助长使用者的邪念，使其堕入魔道，因而也被誉为“剑中邪神”。</p><p>火麟剑刀是一柄具有9L伤害和5破甲的轻剑。<br> 【火麟】：火麟剑在挥舞之时，能够激发剑身上的火麒麟鳞片所蕴含之力量，以灼浪伤人。因此只要你的内力池不为空，你每次攻击时，都会附带1点不可豁免的燃烧点数。<br> 【邪剑】：<br> 火麟剑中蕴含的魔性会祝你不断提升功力，但也会逐渐侵蚀你的心性。每经过一部影片，你的内力池扩大6点，并在攻击检定上获得1点可以叠加的附加成功，但这也会使得你在每经过一部影片时，获得1点无法豁免，永久存在的亢奋点数。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
